{"code": "from hermes_tools import terminal
r = terminal("""python3 << 'PYEOF'
import sys, urllib.request, json
url = 'https://zh.wikipedia.org/w/api.php?action=query&prop=extracts&exintro&explaintext&format=json&titles=%E8%9D%89%E8%8A%B1&redirects=1&utf8=1'
req = urllib.request.Request(url, headers={'User-Agent': 'Mozilla/5.0'})
try:
    data = json.loads(urllib.request.urlopen(req, timeout=10).read().decode('utf-8'))
    pages = data['query']['pages']
    for pid, info in pages.items():
        if 'extract' in info:
            sys.stdout.write(info['extract'][:3000])
        else:
            sys.stdout.write('No extract available')
except Exception as e:
    sys.stdout.write(f'Error: {e}')
sys.stdout.flush()
PYEOF
""", timeout=30)
print(r["output"])
